async function loadQuotes() {
  const response = await fetch('https://dummyjson.com/quotes?limit=3');
  const data = await response.json();

  for (const quote of data.quotes) {
    console.log(`${quote.id}. ${quote.quote} — ${quote.author}`);
  }
}

loadQuotes();

