async function loadProducts() {
  const response = await fetch('https://dummyjson.com/products?limit=10');
  const data = await response.json();

  // Keep only products that cost less than $15
  const cheap = data.products.filter(p => p.price < 15);

  // Extract just the title and price of each
  const summary = cheap.map(p => `${p.title} — $${p.price}`);

  summary.forEach(s => console.log(s));
}

loadProducts();
